208: // ResolveShortnameToFQDN uses metadata information to resolve a reference
209: // to shortname of the service to FQDN
210: func ResolveShortnameToFQDN(hostname string, meta config.Meta) host.Name {
211: 	if len(hostname) == 0 {
212: 		// only happens when the gateway-api BackendRef is invalid
213: 		return ""
214: 	}
215: 	out := hostname
216: 	// Treat the wildcard hostname as fully qualified. Any other variant of a wildcard hostname will contain a `.` too,
217: 	// and skip the next if, so we only need to check for the literal wildcard itself.
218: 	if hostname == "*" {
219: 		return host.Name(out)
220: 	}
221: 
222: 	// if the hostname is a valid ipv4 or ipv6 address, do not append domain or namespace
223: 	if netutil.IsValidIPAddress(hostname) {
224: 		return host.Name(out)
225: 	}
226: 
227: 	// if FQDN is specified, do not append domain or namespace to hostname
228: 	if !strings.Contains(hostname, ".") {
229: 		if meta.Namespace != "" {
230: 			out = out + "." + meta.Namespace
231: 		}
232: 
233: 		// FIXME this is a gross hack to hardcode a service's domain name in kubernetes
234: 		// BUG this will break non kubernetes environments if they use shortnames in the
235: 		// rules.
236: 		if meta.Domain != "" {
237: 			out = out + ".svc." + meta.Domain
238: 		}
239: 	}
240: 
241: 	return host.Name(out)
242: }
