244: // resolveGatewayName uses metadata information to resolve a reference
245: // to shortname of the gateway to FQDN
246: func resolveGatewayName(gwname string, meta config.Meta) string {
247: 	out := gwname
248: 
249: 	// New way of binding to a gateway in remote namespace
250: 	// is ns/name. Old way is either FQDN or short name
251: 	if !strings.Contains(gwname, "/") {
252: 		if !strings.Contains(gwname, ".") {
253: 			// we have a short name. Resolve to a gateway in same namespace
254: 			out = meta.Namespace + "/" + gwname
255: 		} else {
256: 			// parse namespace from FQDN. This is very hacky, but meant for backward compatibility only
257: 			// This is a legacy FQDN format. Transform name.ns.svc.cluster.local -> ns/name
258: 			i := strings.Index(gwname, ".")
259: 			fqdn := strings.Index(gwname[i+1:], ".")
260: 			if fqdn == -1 {
261: 				out = gwname[i+1:] + "/" + gwname[:i]
262: 			} else {
263: 				out = gwname[i+1:i+1+fqdn] + "/" + gwname[:i]
264: 			}
265: 		}
266: 	} else {
267: 		// remove the . from ./gateway and substitute it with the namespace name
268: 		i := strings.Index(gwname, "/")
269: 		if gwname[:i] == "." {
270: 			out = meta.Namespace + "/" + gwname[i+1:]
271: 		}
272: 	}
273: 	return out
274: }
