93: // Push an XDS resource for the given connection. Configuration will be generated
94: // based on the passed in generator. Based on the updates field, generators may
95: // choose to send partial or even no response if there are no changes.
96: func (s *DiscoveryServer) pushXds(con *Connection, w *model.WatchedResource, req *model.PushRequest) error {
97: 	if w == nil {
98: 		return nil
99: 	}
100: 	gen := s.findGenerator(w.TypeUrl, con)
101: 	if gen == nil {
102: 		return nil
103: 	}
104: 
105: 	t0 := time.Now()
106: 
107: 	// If delta is set, client is requesting new resources or removing old ones. We should just generate the
108: 	// new resources it needs, rather than the entire set of known resources.
109: 	// Note: we do not need to account for unsubscribed resources as these are handled by parent removal;
110: 	// See https://www.envoyproxy.io/docs/envoy/latest/api-docs/xds_protocol#deleting-resources.
111: 	// This means if there are only removals, we will not respond.
112: 	var logFiltered string
113: 	if !req.Delta.IsEmpty() && !con.proxy.IsProxylessGrpc() {
114: 		logFiltered = " filtered:" + strconv.Itoa(len(w.ResourceNames)-len(req.Delta.Subscribed))
115: 		w = &model.WatchedResource{
116: 			TypeUrl:       w.TypeUrl,
117: 			ResourceNames: req.Delta.Subscribed.UnsortedList(),
118: 		}
119: 	}
120: 	res, logdata, err := gen.Generate(con.proxy, w, req)
121: 	info := ""
122: 	if len(logdata.AdditionalInfo) > 0 {
123: 		info = " " + logdata.AdditionalInfo
124: 	}
125: 	if len(logFiltered) > 0 {
126: 		info += logFiltered
127: 	}
128: 	if err != nil || res == nil {
129: 		if log.DebugEnabled() {
130: 			log.Debugf("%s: SKIP%s for node:%s%s", v3.GetShortType(w.TypeUrl), req.PushReason(), con.proxy.ID, info)
131: 		}
132: 
133: 		return err
134: 	}
135: 	defer func() { recordPushTime(w.TypeUrl, time.Since(t0)) }()
136: 
137: 	resp := &discovery.DiscoveryResponse{
138: 		ControlPlane: ControlPlane(),
139: 		TypeUrl:      w.TypeUrl,
140: 		// TODO: send different version for incremental eds
141: 		VersionInfo: req.Push.PushVersion,
142: 		Nonce:       nonce(req.Push.PushVersion),
143: 		Resources:   xds.ResourcesToAny(res),
144: 	}
145: 
146: 	configSize := ResourceSize(res)
147: 	configSizeBytes.With(typeTag.Value(w.TypeUrl)).Record(float64(configSize))
148: 
149: 	ptype := "PUSH"
150: 	if logdata.Incremental {
151: 		ptype = "PUSH INC"
152: 	}
153: 
154: 	if err := xds.Send(con, resp); err != nil {
155: 		if recordSendError(w.TypeUrl, err) {
156: 			log.Warnf("%s: Send failure for node:%s resources:%d size:%s%s: %v",
157: 				v3.GetShortType(w.TypeUrl), con.proxy.ID, len(res), util.ByteCount(configSize), info, err)
158: 		}
159: 		return err
160: 	}
161: 
162: 	switch {
163: 	case !req.Full:
164: 		if log.DebugEnabled() {
165: 			log.Debugf("%s: %s%s for node:%s resources:%d size:%s%s",
166: 				v3.GetShortType(w.TypeUrl), ptype, req.PushReason(), con.proxy.ID, len(res), util.ByteCount(configSize), info)
167: 		}
168: 	default:
169: 		debug := ""
170: 		if log.DebugEnabled() {
171: 			// Add additional information to logs when debug mode enabled.
172: 			debug = " nonce:" + resp.Nonce + " version:" + resp.VersionInfo
173: 		}
174: 		log.Infof("%s: %s%s for node:%s resources:%d size:%v%s%s", v3.GetShortType(w.TypeUrl), ptype, req.PushReason(), con.proxy.ID, len(res),
175: 			util.ByteCount(ResourceSize(res)), info, debug)
176: 	}
177: 
178: 	return nil
179: }
