181: func ResourceSize(r model.Resources) int {
182: 	// Approximate size by looking at the Any marshaled size. This avoids high cost
183: 	// proto.Size, at the expense of slightly under counting.
184: 	size := 0
185: 	for _, r := range r {
186: 		size += len(r.Resource.Value)
187: 	}
188: 	return size
189: }
