218: // Push metrics are updated periodically (10s default)
219: func (s *DiscoveryServer) periodicRefreshMetrics(stopCh <-chan struct{}) {
220: 	ticker := time.NewTicker(periodicRefreshMetrics)
221: 	defer ticker.Stop()
222: 	for {
223: 		select {
224: 		case <-ticker.C:
225: 			push := s.globalPushContext()
226: 			model.LastPushMutex.Lock()
227: 			if model.LastPushStatus != push {
228: 				model.LastPushStatus = push
229: 				push.UpdateMetrics()
230: 				out, _ := model.LastPushStatus.StatusJSON()
231: 				if string(out) != "{}" {
232: 					log.Infof("Push Status: %s", string(out))
233: 				}
234: 			}
235: 			model.LastPushMutex.Unlock()
236: 		case <-stopCh:
237: 			return
238: 		}
239: 	}
240: }
