242: // dropCacheForRequest clears the cache in response to a push request
243: func (s *DiscoveryServer) dropCacheForRequest(req *model.PushRequest) {
244: 	// If we don't know what updated, cannot safely cache. Clear the whole cache
245: 	if len(req.ConfigsUpdated) == 0 {
246: 		s.Cache.ClearAll()
247: 	} else {
248: 		// Otherwise, just clear the updated configs
249: 		s.Cache.Clear(req.ConfigsUpdated)
250: 	}
251: }
