503: // initPushContext creates a global push context and stores it on the environment. Note: while this
504: // method is technically thread safe (there are no data races), it should not be called in parallel;
505: // if it is, then we may start two push context creations (say A, and B), but then write them in
506: // reverse order, leaving us with a final version of A, which may be incomplete.
507: func (s *DiscoveryServer) initPushContext(req *model.PushRequest, oldPushContext *model.PushContext, version string) (*model.PushContext, error) {
508: 	push := model.NewPushContext()
509: 	push.PushVersion = version
510: 	push.JwtKeyResolver = s.JwtKeyResolver
511: 	if err := push.InitContext(s.Env, oldPushContext, req); err != nil {
512: 		log.Errorf("XDS: failed to init push context: %v", err)
513: 		// We can't push if we can't read the data - stick with previous version.
514: 		pushContextErrors.Increment()
515: 		return nil, err
516: 	}
517: 
518: 	s.dropCacheForRequest(req)
519: 	s.Env.SetPushContext(push)
520: 
521: 	return push, nil
522: }
