534: // Clients returns all currently connected clients. This method can be safely called concurrently,
535: // but care should be taken with the underlying objects (ie model.Proxy) to ensure proper locking.
536: // This method returns only fully initialized connections; for all connections, use AllClients
537: func (s *DiscoveryServer) Clients() []*Connection {
538: 	s.adsClientsMutex.RLock()
539: 	defer s.adsClientsMutex.RUnlock()
540: 	clients := make([]*Connection, 0, len(s.adsClients))
541: 	for _, con := range s.adsClients {
