553: // SortedClients returns all currently connected clients in an ordered manner.
554: // Sorting order priority is as follows: ClusterID, Namespace, ID.
555: func (s *DiscoveryServer) SortedClients() []*Connection {
556: 	clients := s.Clients()
557: 	sort.Slice(clients, func(i, j int) bool {
558: 		if clients[i].proxy.GetClusterID().String() < clients[j].proxy.GetClusterID().String() {
559: 			return true
560: 		}
561: 		if clients[i].proxy.GetNamespace() < clients[j].proxy.GetNamespace() {
562: 			return true
563: 		}
564: 		return clients[i].proxy.GetID() < clients[j].proxy.GetID()
565: 	})
566: 	return clients
567: }
